uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 uv2 = vUv;
uv2.x=1-uv2.x;
uv2 = .5+(uv2-.5)*.98;
vUv = 0.5 + (vUv-0.5)*0.98;
    vec2 d = uTexSize.zw*4;
    vec2 d2= uTexSize.zw*4;

    vec3 dx = ( GetBlur1(vUv+vec2(1,0)*d)-GetBlur1(vUv-vec2(1,0)*d) );
    vec3 dx2= ( GetBlur1(uv2+vec2(1,0)*d2)-GetBlur1(uv2-vec2(1,0)*d2) );

    vec3 dy = ( GetBlur1(vUv+vec2(0,1)*d)-GetBlur1(vUv-vec2(0,1)*d) );
    vec3 dy2 = ( GetBlur1(uv2+vec2(0,1)*d2)-GetBlur1(uv2-vec2(0,1)*d2) );

vec4 noise = texture3D(sampler_noisevol_hq, ((vUv.xyy+vec3(lum(dx),lum(dy),0)*0.5)*uTexSize.xyy*texsize_noisevol_hq.zww).xyz*vec3(1,1,0)*0.05
                                        + uTime*vec3(0,0,1)*0.2 );
vec4 noise2= texture3D(sampler_noisevol_hq, ((uv2.xyy+vec3(lum(dx2),lum(dy2),0)*0.5)*uTexSize.xyy*texsize_noisevol_hq.zww).xyz*vec3(1,1,0)*0.05
                                        + uTime*vec3(0,0,1)*0.2 );
vUv -= vec2(lum(dx),lum(dy))*0.04;
uv2-= vec2(lum(dx2),lum(dy2))*0.04;

ret = abs(GetPixel(vUv)+GetBlur1(vUv)-GetBlur2(vUv)-GetBlur3(vUv));
vec3 ret2 = abs(GetPixel(uv2)+GetBlur1(uv2)-GetBlur2(uv2)-GetBlur3(uv2));
ret *= lum(noise)*3;
ret2*= lum(noise)*3;
ret = pow(ret,0.5);
ret2= pow(ret2,0.5);
ret2=.5-ret2;
ret-=.3-ret2;

  fragColor = ret;
}
